const board = 'Tech_Job';
const keyword = 'AI';
const url = 'https://www.ptt.cc/bbs/' + board + '/search?q=' + encodeURIComponent(keyword);
return [{ json: { board, keyword, url } }];

const j = $input.first().json;
const html = j.data || j.body || '';
const re = /<div class=\x22title\x22>\s*<a href=\x22([^\x22]+)\x22>([^<]+)<\/a>/g;
const items = []; let m;
while ((m = re.exec(html)) !== null) {
  const title = m[2].replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').trim();
  items.push({ title, link: 'https://www.ptt.cc' + m[1] });
  if (items.length >= 20) break;
}
const meta = $('Input (edit me)').first().json;
const list = items.map((n, i) => (i + 1) + '. ' + n.title).join('\n');
const prompt = '以下是 PTT「' + meta.board + '」版搜尋「' + meta.keyword + '」的最新討論標題。請用繁體中文整理成輿情報告：\n1) 主要討論什麼（2-4 個重點）\n2) 整體風向與情緒（正面/負面/中立，並簡述）\n3) 值得品牌注意的點\n\n標題清單：\n' + (list || '（這次沒抓到標題，可能是看板或關鍵字需調整）');
return [{ json: { count: items.length, prompt } }];

const data = $input.first().json;
let summary = '';
try { summary = (data.message && data.message.content) || (data.content && data.content[0] && data.content[0].text) || data.response || ''; } catch (e) {}
if (!summary) summary = JSON.stringify(data);
return [{ json: { summary } }];
